-- Luke Chapter 12
-- Theme: Watchfulness, Stewardship, and Undivided Allegiance
-- 59 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 12,
  'Luke 12 is one of the longest chapters in the Gospel and one of the most theologically rich in the entire NT. It opens with Jesus addressing his disciples in the presence of a surging crowd (vv.1-12): a warning against Pharisaic hypocrisy whose hidden corruption will inevitably be exposed, a call to fear God rather than men, and the assurance that the Holy Spirit will provide words when disciples face persecution. The chapter pivots on a request from the crowd about an inheritance dispute (vv.13-15), which Jesus refuses to adjudicate — not because justice is unimportant but because covetousness, not the legal question, is the real problem.' ||
  'The parable of the rich fool (vv.16-21) is one of Luke''s most arresting narratives: a prosperous farmer who, in a night of grand plans for security and self-indulgence, hears the word "fool" from God and loses everything. He was "rich toward self" but "not rich toward God." This leads directly into the extended teaching on anxiety and trust (vv.22-34), where Jesus draws on the ravens and lilies as living sermons of divine provision, climaxing in the command to "seek the kingdom" and the tender assurance: "Fear not, little flock; it is your Father''s good pleasure to give you the kingdom."' ||
  'The second half of the chapter addresses watchfulness (vv.35-48): the disciples are to be dressed for service, lamps burning, like servants awaiting a master who could return at any hour. The parable of the faithful steward (vv.41-48) introduces the principle of proportional accountability: to whom much is given, much will be required. This applies with particular force to those who know the master''s will — teachers, leaders, apostles — who face greater judgment for unfaithful stewardship.' ||
  'The chapter closes with three sombre sayings: the fire Jesus came to cast on the earth (v.49), his baptism of suffering not yet accomplished (v.50), and the division that his coming will produce in the closest human relationships (vv.51-53). The final section (vv.54-59) turns to the crowd with a rebuke about spiritual discernment: they can read weather signs but cannot read the signs of the eschatological moment. The call to settle with one''s adversary before reaching the judge applies both to interpersonal reconciliation and to the urgency of responding to Jesus before the day of judgment arrives.',
  'Watchfulness, Stewardship, and Undivided Allegiance',
  'φυλάσσω (phulassō)',
  'phulassō means to guard, keep watch over, to preserve and protect. It appears in this chapter''s call to watchfulness (v.15: "beware of covetousness") and frames the entire discourse on readiness: disciples are to guard their hearts against anxiety and greed, keep their lamps burning, and watch for the master''s return. The word captures the active, alert posture that Luke 12 demands — not passive waiting but intentional vigilance over one''s inner life, stewardship, and eschatological readiness.',
  '["Beware of Hypocrisy: Fear God and Confess Christ (vv.1-12)","The Parable of the Rich Fool: Wealth Without God (vv.13-21)","Freedom from Anxiety: Seek First the Kingdom (vv.22-34)","Watchful Stewardship: Faithful Servants Awaiting the Master (vv.35-48)","Fire, Division, and the Urgency of This Hour (vv.49-59)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'In the mean time, when there were gathered together an innumerable multitude of people, insomuch that they trode one upon another, he began to say unto his disciples first of all, Beware ye of the leaven of the Pharisees, which is hypocrisy.', 'Ἐν οἷς ἐπισυναχθεισῶν τῶν μυριάδων τοῦ ὄχλου, ὥστε καταπατεῖν ἀλλήλους, ἤρξατο λέγειν πρὸς τοὺς μαθητὰς αὐτοῦ πρῶτον, Προσέχετε ἑαυτοῖς ἀπὸ τῆς ζύμης τῶν Φαρισαίων, ἥτις ἐστὶν ὑπόκρισις.', 'En hois episunachtheisōn tōn muriadōn tou ochlou, hōste katapatein allēlous, ērxato legein pros tous mathētas autou prōton, Prosechete heautois apo tēs zumēs tōn Pharisaiōn, hētis estin hupokrisis.', '"Innumerable multitude" (muriadōn — ten-thousands, myriads) indicates enormous crowds pressing together. Significantly, Jesus turns first to his disciples — not the crowd — and warns them before all else of leaven (zumēs — a hidden, pervasive fermenting agent). Hypocrisy (hupokrisis — playing a role, acting a part from Greek theater) is the leaven of Pharisaism: a tiny amount invisibly permeates and corrupts the whole batch. The warning is preventive medicine for disciples under public pressure.', NULL),
  (2, 'For there is nothing covered, that shall not be revealed; neither hid, that shall not be known.', 'οὐδὲν δὲ συγκεκαλυμμένον ἐστὶν ὃ οὐκ ἀποκαλυφθήσεται, καὶ κρυπτὸν ὃ οὐ γνωσθήσεται.', 'ouden de sungkekalummenon estin ho ouk apokaluphthēsetai, kai krupton ho ou gnōsthēsetai.', 'The guarantee that makes hypocrisy ultimately futile: the divine light will penetrate every concealment. "Revealed" (apokaluphthēsetai — apocalypsed, unveiled) and "known" (gnōsthēsetai) are divine passives — God will be the one who discloses. The eschatological judgment is the ultimate unmasking. This verse applies to the Pharisees'' hidden corruption (11:44) and simultaneously assures disciples that their persecutors'' tactics will be exposed.', NULL),
  (3, 'Therefore whatsoever ye have spoken in darkness shall be heard in the light; and that which ye have spoken in the ear in closets shall be proclaimed upon the housetops.', 'ἀνθ'' ὧν ὅσα ἐν τῇ σκοτίᾳ εἴπατε ἐν τῷ φωτὶ ἀκουσθήσεται, καὶ ὃ πρὸς τὸ οὖς ἐλαλήσατε ἐν τοῖς ταμείοις κηρυχθήσεται ἐπὶ τῶν δωμάτων.', 'anth'' hōn hosa en tē skotia eipate en tō phōti akousthēsetai, kai ho pros to ous elalēsate en tois tameiois kēruchthēsetai epi tōn dōmatōn.', 'The antithesis is complete: darkness/light, whispered/proclaimed, inner room/housetop. The flat rooftops of Palestinian homes were used for public announcements. The saying may apply to both negative exposure (the Pharisees'' hidden corruption will be exposed) and positive proclamation (what disciples receive privately from Jesus will be preached publicly). Secrecy is temporary; the word of God is ultimately public.', NULL),
  (4, 'And I say unto you my friends, Be not afraid of them that kill the body, and after that have no more that they can do.', 'Λέγω δὲ ὑμῖν τοῖς φίλοις μου, μὴ φοβηθῆτε ἀπὸ τῶν ἀποκτεννόντων τὸ σῶμα, καὶ μετὰ ταῦτα μὴ ἐχόντων περισσότερόν τι ποιῆσαι.', 'Legō de humin tois philois mou, mē phobēthēte apo tōn apoktennontōn to sōma, kai meta tauta mē echontōn perissoteron ti poiēsai.', '"My friends" (tois philois mou) — a warm, intimate address that appears rarely in the Gospels. Jesus calls his disciples friends (John 15:14-15), not merely servants. The limit of human power over disciples is the body — after killing, persecutors "have no more that they can do" (perissoteron — nothing exceeding, no additional power). This is the foundation of Christian fearlessness: the worst humans can do is remove what God can restore at resurrection.', NULL),
  (5, 'But I will forewarn you whom ye shall fear: Fear him, which after he hath killed hath power to cast into hell; yea, I say unto you, Fear him.', 'ὑποδείξω δὲ ὑμῖν τίνα φοβηθῆτε· φοβήθητε τὸν μετὰ τὸ ἀποκτεῖναι ἔχοντα ἐξουσίαν ἐμβαλεῖν εἰς τὴν γέενναν· ναί, λέγω ὑμῖν, τοῦτον φοβήθητε.', 'hupodeixō de humin tina phobēthēte; phobēthēte ton meta to apokteinai echonta exousian embalein eis tēn geennan; nai, legō humin, touton phobēthēte.', 'The fear of God is presented not as the abolition of fear but as its right object. God''s authority (exousian) extends beyond death — he has power to cast into Gehenna (geennan — the valley of Hinnom south of Jerusalem, used for refuse burning, a symbol of final judgment). The double "Fear him" gives the command rare rhetorical weight. Right fear of God displaces all lesser fears of human agents.', NULL),
  (6, 'Are not five sparrows sold for two farthings, and not one of them is forgotten before God?', 'οὐχὶ πέντε στρουθία πωλοῦνται ἀσσαρίων δύο; καὶ ἓν ἐξ αὐτῶν οὐκ ἔστιν ἐπιλελησμένον ἐνώπιον τοῦ Θεοῦ.', 'ouchi pente strouthia pōlountai assariōn duo; kai hen ex autōn ouk estin epilelēsmenon enōpion tou Theou.', 'Five sparrows for two farthings (assariōn — the assarion was a small copper coin, worth 1/16 of a denarius). Luke''s five sparrows for two farthings is better value than Matthew''s two sparrows for one farthing (10:29) — the fifth comes free, yet not even the free sparrow is forgotten (epilelēsmenon — perfect passive: has been forgotten) by God. The argument is from lesser to greater: if God remembers every market sparrow, how much more will he remember his disciples?', NULL),
  (7, 'But even the very hairs of your head are all numbered. Fear not therefore: ye are of more value than many sparrows.', 'ἀλλὰ καὶ αἱ τρίχες τῆς κεφαλῆς ὑμῶν πᾶσαι ἠρίθμηνται. μὴ φοβεῖσθε· πολλῶν στρουθίων διαφέρετε.', 'alla kai hai triches tēs kephalēs humōn pasai ērithmēntai. mē phobeisthe; pollōn strouthiōn diapherete.', '"Numbered" (ērithmēntai — perfect passive: have been counted and the count stands) — not a general approximation but a specific ongoing enumeration. The hairs of the head were proverbially uncountable (Ps 40:12); yet God''s knowledge extends even to this detail. "Ye are of more value" (diapherete — you differ from, surpass) many sparrows. The comparison establishes not arrogance but assurance: disciples are infinitely more precious to God than the creatures he does not forget.', NULL),
  (8, 'Also I say unto you, Whosoever shall confess me before men, him shall the Son of man also confess before the angels of God:', 'Λέγω δὲ ὑμῖν, πᾶς ὃς ἂν ὁμολογήσῃ ἐν ἐμοὶ ἔμπροσθεν τῶν ἀνθρώπων, καὶ ὁ Υἱὸς τοῦ ἀνθρώπου ὁμολογήσει ἐν αὐτῷ ἔμπροσθεν τῶν ἀγγέλων τοῦ Θεοῦ·', 'Legō de humin, pas hos an homologēsē en emoi emprosthen tōn anthrōpōn, kai ho Huios tou anthrōpou homologēsei en autō emprosthen tōn angelōn tou Theou;', '"Confess me" (homologēsē en emoi — to speak the same word as, to agree with, to publicly acknowledge) — a courtroom term. The preposition en ("in me") indicates more than verbal affirmation: identification with Jesus. The cosmic reciprocity is exact: confess before men → confessed before angels; deny before men → denied before angels. The "angels of God" as witnesses at the eschatological tribunal (Dan 7:10; Rev 5:11) gives this solemn heavenly weight.', NULL),
  (9, 'But he that denieth me before men shall be denied before the angels of God.', 'ὁ δὲ ἀρνησάμενός με ἐνώπιον τῶν ἀνθρώπων ἀπαρνηθήσεται ἐνώπιον τῶν ἀγγέλων τοῦ Θεοῦ.', 'ho de arnēsamenos me enōpion tōn anthrōpōn aparnēthēsetai enōpion tōn angelōn tou Theou.', '"Denieth" (arnēsamenos — aorist: who has denied, made a definitive repudiation) stands against "confesseth" in v.8. The divine passive "shall be denied" (aparnēthēsetai) indicates that the Son of Man will be the agent of denial before the heavenly court. This is not a word about momentary weakness (Peter denied but was restored) but about a settled, unrepented posture of repudiation. The angels as witnesses emphasize the eschatological gravity.', NULL),
  (10, 'And whosoever shall speak a word against the Son of man, it shall be forgiven him: but unto him that blasphemeth against the Holy Ghost it shall not be forgiven.', 'καὶ πᾶς ὃς ἐρεῖ λόγον εἰς τὸν Υἱὸν τοῦ ἀνθρώπου, ἀφεθήσεται αὐτῷ· τῷ δὲ εἰς τὸ Ἅγιον Πνεῦμα βλασφημήσαντι οὐκ ἀφεθήσεται.', 'kai pas hos erei logon eis ton Huion tou anthrōpou, aphethēsetai autō; tō de eis to Hagion Pneuma blasphēmēsanti ouk aphethēsetai.', 'This is among the most sobering verses in the Gospels. Speaking against the Son of Man — misunderstanding or even opposing Jesus in his earthly, veiled form — is forgivable because it may arise from ignorance (cf. Paul, 1 Tim 1:13). But blaspheming against the Holy Spirit — the deliberate, settled attribution of the Spirit''s clear works to Satan (as the Pharisees did in 11:15) — is the sin that cannot be forgiven because it severs the very connection through which forgiveness comes.', NULL),
  (11, 'And when they bring you unto the synagogues, and unto magistrates, and powers, take ye no thought how or what thing ye shall answer, or what ye shall say:', 'ὅταν δὲ εἰσφέρωσιν ὑμᾶς ἐπὶ τὰς συναγωγὰς καὶ τὰς ἀρχὰς καὶ τὰς ἐξουσίας, μὴ μεριμνήσητε πῶς ἢ τί ἀπολογήσησθε ἢ τί εἴπητε·', 'hotan de eispherōsin humas epi tas sunagōgas kai tas archas kai tas exousias, mē merimnēsēte pōs ē ti apologēsēsthe ē ti eipēte;', '"Synagogues" (religious court), "magistrates" (archas — rulers, officials), and "powers" (exousias — authorities, governmental forces) together cover all the arenas of persecution disciples would face. "Take ye no thought" (mē merimnēsēte — do not be anxious, do not worry beforehand) is not a prohibition of preparation but of anxious preoccupation. The prohibition specifically applies to the moment of crisis (v.12: "in the same hour"), not to careful long-term teaching.', NULL),
  (12, 'For the Holy Ghost shall teach you in the same hour what ye ought to say.', 'τὸ γὰρ Ἅγιον Πνεῦμα διδάξει ὑμᾶς ἐν αὐτῇ τῇ ὥρᾳ ἃ δεῖ εἰπεῖν.', 'to gar Hagion Pneuma didaxei humas en autē tē hōra ha dei eipein.', '"In the same hour" (en autē tē hōra) — the moment of trial, not beforehand. The Holy Spirit as teacher-in-crisis (didaxei — future: will teach) provides the specific answer for the specific moment. This promise, fulfilled dramatically in Acts (4:8; 6:10; 7:1-53), assumes dependence on the Spirit rather than autonomous eloquence. "What ye ought to say" (ha dei eipein — what it is necessary to say) implies the Spirit''s speech serves the divine redemptive agenda.', NULL),
  (13, 'And one of the company said unto him, Master, speak to my brother, that he divide the inheritance with me.', 'Εἶπεν δέ τις αὐτῷ ἐκ τοῦ ὄχλου, Διδάσκαλε, εἰπὲ τῷ ἀδελφῷ μου μερίσασθαι μετ'' ἐμοῦ τὴν κληρονομίαν.', 'Eipen de tis autō ek tou ochlou, Didaskale, eipe tō adelphō mou merisasthai met'' emou tēn klēronomian.', 'The sudden interruption from the crowd is jarring — Jesus has been speaking of martyrdom and the Holy Spirit, and a man calls out about an inheritance dispute. This is a realistic portrait of human self-absorption. The request was culturally reasonable: rabbis frequently adjudicated family legal disputes. But the man''s concern for his share while standing before the Lord of glory reveals misaligned priorities.', NULL),
  (14, 'And he said unto him, Man, who made me a judge or a divider over you?', 'ὁ δὲ εἶπεν αὐτῷ, Ἄνθρωπε, τίς με κατέστησεν κριτὴν ἢ μεριστὴν ἐφ'' ὑμᾶς;', 'ho de eipen autō, Anthrōpe, tis me katestēsen kritēn ē meristēn eph'' humas?', '"Man" (anthrōpe) — a gentle but distancing form of address, less warm than "friend" (4). Jesus refuses the judicial role not because inheritance justice is unimportant but because it is not his mission and because the questioner''s real problem is not his brother''s injustice but his own covetousness. The question echoes Moses in Exod 2:14; Jesus is a different kind of deliverer — one who addresses the heart, not the courtroom.', NULL),
  (15, 'And he said unto them, Take heed, and beware of covetousness: for a man''s life consisteth not in the abundance of the things which he possesseth.', 'εἶπεν δὲ πρὸς αὐτούς, Ὁρᾶτε καὶ φυλάσσεσθε ἀπὸ πάσης πλεονεξίας· ὅτι οὐκ ἐν τῷ περισσεύειν τινὶ ἡ ζωὴ αὐτοῦ ἐστιν ἐκ τῶν ὑπαρχόντων αὐτοῦ.', 'eipen de pros autous, Horate kai phulassesthe apo pasēs pleonexias; hoti ouk en tō perisseuein tini hē zōē autou estin ek tōn huparchontōn autou.', 'Turning the private request into a public teaching moment, Jesus addresses "them" (the crowd). "Covetousness" (pleonexia — greed, the desire to have more, literally "the wanting of more"). "Life" (zōē — the true life, genuine human existence) "consisteth not" (ouk estin — is not) in the abundance of possessions. This is a direct contradiction of the prosperity assumption embedded in the man''s request and in much ancient and modern thinking.', NULL),
  (16, 'And he spake a parable unto them, saying, The ground of a certain rich man brought forth plentifully:', 'Εἶπεν δὲ παραβολὴν πρὸς αὐτούς, λέγων, Ἀνθρώπου τινὸς πλουσίου εὐφόρησεν ἡ χώρα·', 'Eipen de parabolēn pros autous, legōn, Anthrōpou tinos plousiou euphorēsen hē chōra;', 'The parable of the rich fool follows immediately as the illustrative narrative for v.15. "The ground brought forth plentifully" (euphorēsen — bore abundantly) — the extraordinary harvest is a gift from God, not the achievement of the rich man. The man''s response to divine abundance will reveal his character. Crucially, there is no villain in this story except covetousness itself: no one has wronged him.', NULL),
  (17, 'And he thought within himself, saying, What shall I do, because I have no room where to bestow my fruits?', 'καὶ διελογίζετο ἐν ἑαυτῷ λέγων, Τί ποιήσω, ὅτι οὐκ ἔχω ποῦ συνάξω τοὺς καρπούς μου;', 'kai dielogizeto en heautō legōn, Ti poiēsō, hoti ouk echō pou sunaxō tous karpous mou?', '"Thought within himself" (dielogizeto en heautō) — internal deliberation, a monologue. The question "What shall I do?" is not asked of God, neighbors, or family — only of himself. The pronouns in the following verses are almost exclusively first person singular: my fruits, my barns, my goods, my soul. This relentless self-reference is the portrait of a soul sealed off from God and neighbor by material abundance.', NULL),
  (18, 'And he said, This will I do: I will pull down my barns, and build greater; and there will I bestow all my fruits and my goods.', 'καὶ εἶπεν, Τοῦτο ποιήσω· καθελῶ μου τὰς ἀποθήκας καὶ μείζονας οἰκοδομήσω, καὶ συνάξω ἐκεῖ πάντα τὰ γενήματά μου καὶ τὰ ἀγαθά μου.', 'kai eipen, Touto poiēsō; kathelō mou tas apothēkas kai meizsonas oikodomēsō, kai sunaxō ekei panta ta genēmata mou kai ta agatha mou.', 'The solution is purely architectural — build bigger barns — rather than redistributive (share with the poor) or devotional (return thanks to God). "Pull down" (kathelō — demolish) and "build greater" reveals that more is always the answer when material security is the goal. The phrase "all my fruits and my goods" — everything accumulated into self-storage — is the opposite of the kingdom generosity Jesus teaches throughout Luke.', NULL),
  (19, 'And I will say to my soul, Soul, thou hast much goods laid up for many years; take thine ease, eat, drink, and be merry.', 'καὶ ἐρῶ τῇ ψυχῇ μου, Ψυχή, ἔχεις πολλὰ ἀγαθὰ κείμενα εἰς ἔτη πολλά· ἀναπαύου, φάγε, πίε, εὐφραίνου.', 'kai erō tē psuchē mou, Psuchē, echeis polla agatha keimena eis etē polla; anapauou, phage, pie, euphrianou.', 'The man addresses his soul — the real self, the person — and promises it material comfort. The tragic irony is that he confuses the material with the personal: "much goods" cannot satisfy a soul, which was made for God. "Many years" — but the night of this very speech, his soul will be required. "Eat, drink, and be merry" echoes Eccl 8:15; Isa 22:13 — the philosophy of those who have forgotten God and death.', NULL),
  (20, 'But God said unto him, Thou fool, this night thy soul shall be required of thee: then whose shall those things be, which thou hast provided?', 'εἶπεν δὲ αὐτῷ ὁ Θεός, Ἄφρων, ταύτῃ τῇ νυκτὶ τὴν ψυχήν σου ἀπαιτοῦσιν ἀπὸ σοῦ· ἃ δὲ ἡτοίμασας, τίνι ἔσται;', 'eipen de autō ho Theos, Aphrōn, tautē tē nukti tēn psuchēn sou apaitousin apo sou; ha de hētoimasas, tini estai?', '"God said" — the divine voice interrupts the human monologue for the first and only time in the parable. "Thou fool" (Aphrōn — senseless, one who lacks understanding, the opposite of sophia) — not a casual insult but a moral-theological verdict (Ps 14:1). "This night" (tautē tē nukti) — the very night of grand planning is the night of death. "Thy soul shall be required of thee" (apaitousin — they will demand back, recall as a loan) suggests life is borrowed, not owned.', NULL),
  (21, 'So is he that layeth up treasure for himself, and is not rich toward God.', 'οὕτως ὁ θησαυρίζων ἑαυτῷ καὶ μὴ εἰς Θεὸν πλουτῶν.', 'houtōs ho thēsaurizōn heautō kai mē eis Theon ploutōn.', 'The parable''s interpretation is given directly — rare in the Synoptics. "Layeth up treasure for himself" (thēsaurizōn heautō — hoarding toward oneself) is contrasted with "rich toward God" (eis Theon ploutōn — becoming rich in the direction of God). Richness toward God includes generosity, reliance on him, and investment in his kingdom. The contrast is not wealth versus poverty but self-directed versus God-directed stewardship.', NULL),
  (22, 'And he said unto his disciples, Therefore I say unto you, Take no thought for your life, what ye shall eat; neither for the body, what ye shall put on.', 'Εἶπεν δὲ πρὸς τοὺς μαθητὰς αὐτοῦ, Διὰ τοῦτο λέγω ὑμῖν, μὴ μεριμνᾶτε τῇ ψυχῇ τί φάγητε, μηδὲ τῷ σώματι τί ἐνδύσησθε.', 'Eipen de pros tous mathētas autou, Dia touto legō humin, mē merimnate tē psuchē ti phagēte, mēde tō sōmati ti endusēsthe.', '"Therefore" (dia touto) connects the warning against anxiety directly to the parable of the rich fool. "Take no thought" (mē merimnate — stop being anxious, do not be preoccupied with worry) is a present imperative prohibition: cease a current practice. The rich fool was anxious about abundance; disciples may be anxious about want. Both are the same root disease: failure to trust the Father''s provision.', NULL),
  (23, 'The life is more than meat, and the body is more than raiment.', 'ἡ γὰρ ψυχὴ πλεῖόν ἐστιν τῆς τροφῆς, καὶ τὸ σῶμα τοῦ ἐνδύματος.', 'hē gar psuchē pleion estin tēs trophēs, kai to sōma tou endumatos.', 'A logical argument a maiori ad minus: if God has given the greater (life, body), will he not also give the lesser (food, clothing)? The soul/life (psuchē) is infinitely more valuable than the food that sustains it; the body more valuable than the clothing that covers it. To worry about food and clothing while possessing life and body is to anxiously guard the lesser while the greater is already secured by God.', NULL),
  (24, 'Consider the ravens: for they neither sow nor reap; which neither have storehouse nor barn; and God feedeth them: how much more are ye better than the fowls?', 'κατανοήσατε τοὺς κόρακας ὅτι οὐ σπείρουσιν οὐδὲ θερίζουσιν, οἷς οὐκ ἔστιν ταμεῖον οὐδὲ ἀποθήκη, καὶ ὁ Θεὸς τρέφει αὐτούς· πόσῳ μᾶλλον ὑμεῖς διαφέρετε τῶν πετεινῶν.', 'katanoēsate tous korakas hoti ou speirousin oude therizousin, hois ouk estin tameion oude apothēkē, kai ho Theos trephei autous; posō mallon humeis diapherete tōn peteinōn.', '"Consider" (katanoēsate — contemplate carefully, study attentively) — not a casual glance but meditative observation. Luke uses ravens (korakas), which were unclean birds (Lev 11:15), heightening the point: God feeds even ceremonially unclean creatures. No storehouse, no barn — yet fed. The a fortiori question is decisive: "how much more are ye better" (posō mallon diapherete — how much more you differ from/surpass). If God feeds the ravens, his children are incomparably more precious.', NULL),
  (25, 'And which of you with taking thought can add to his stature one cubit?', 'τίς δὲ ἐξ ὑμῶν μεριμνῶν δύναται ἐπὶ τὴν ἡλικίαν αὐτοῦ προσθεῖναι πῆχυν;', 'tis de ex humōn merimnōn dunatai epi tēn hēlikian autou prostheinai pēchun?', '"Stature" (hēlikian) may mean height or lifespan (both meanings are attested). Either way the argument holds: anxiety cannot add a single cubit to one''s physical stature or a single moment to one''s lifespan. The absurdity of worrying about what anxiety cannot change is exposed. Worry is not only spiritually wrong but practically useless — it neither produces the thing feared nor prevents it.', NULL),
  (26, 'If ye then be not able to do that thing which is least, why take ye thought for the rest?', 'εἰ οὖν οὐδὲ ἐλάχιστον δύνασθε, τί περὶ τῶν λοιπῶν μεριμνᾶτε;', 'ei oun oude elachiston dunasthe, ti peri tōn loipōn merimnate?', 'The rhetorical conclusion from v.25: if you cannot do the least thing (add a cubit by worrying), why be anxious about the greater things? The logic dismantles anxiety''s pretension to usefulness. If worry is powerless over the smallest matter of existence, it is equally powerless over larger ones. The cure is not greater effort of mind but greater trust in God.', NULL),
  (27, 'Consider the lilies how they grow: they toil not, they spin not; and yet I say unto you, that Solomon in all his glory was not arrayed like one of these.', 'κατανοήσατε τὰ κρίνα πῶς αὐξάνει· οὐ κοπιᾷ οὐδὲ νήθει· λέγω δὲ ὑμῖν, οὐδὲ Σολομὼν ἐν πάσῃ τῇ δόξῃ αὐτοῦ περιεβάλετο ὡς ἓν τούτων.', 'katanoēsate ta krina pōs auxanei; ou kopiā oude nēthei; legō de humin, oude Solomōn en pasē tē doxē autou periebaleto hōs hen toutōn.', 'The second creation-sermon: "Consider the lilies" — not just observe but study them attentively. The lilies "toil not" (ou kopiā — do not labor) and "spin not" (ou nēthei — do not weave), yet they are clothed in splendor surpassing Solomon. The royal courts of Solomon — Israel''s wealthiest king — represent the pinnacle of human-made beauty. Yet a single field flower, dressed by God, exceeds it. The comparison is not merely aesthetic but theological: God''s provision is incomparably superior to human achievement.', NULL),
  (28, 'If then God so clothe the grass, which is to day in the field, and to morrow is cast into the oven; how much more will he clothe you, O ye of little faith?', 'εἰ δὲ τὸν χόρτον ἐν τῷ ἀγρῷ σήμερον ὄντα καὶ αὔριον εἰς κλίβανον βαλλόμενον ὁ Θεὸς οὕτως ἀμφιέζει, πόσῳ μᾶλλον ὑμᾶς, ὀλιγόπιστοι.', 'ei de ton chorton en tō agrō sēmeron onta kai aurion eis klibanon ballomenon ho Theos houtōs amphiezei, posō mallon humas, oligopistoi.', 'The grass (chorton — the wild flowers, the whole category of field vegetation) is today in the field and tomorrow cast into the bread-oven as fuel — a brief, transient existence. Yet God clothes it magnificently. The a fortiori climax is personal and gentle: "O ye of little faith" (oligopistoi — a tender word, not a condemnation, acknowledging real but insufficient faith). The disciples have faith; they need more trust, not more activity.', NULL),
  (29, 'And seek not ye what ye shall eat, or what ye shall drink, neither be ye of doubtful mind.', 'καὶ ὑμεῖς μὴ ζητεῖτε τί φάγητε καὶ τί πίητε, καὶ μὴ μετεωρίζεσθε.', 'kai humeis mē zēteite ti phagēte kai ti piēte, kai mē meteōrizesthe.', '"Seek not" (mē zēteite — stop seeking) in contrast to "seek the kingdom" (zēteite tēn basileian) in v.31. The forbidden seeking is material preoccupation; the commanded seeking is kingdom orientation. "Be ye of doubtful mind" (meteōrizesthe — to be suspended in anxiety, to be tossed up like a ship on waves, literally to be "airborne with worry") is a vivid image of mental agitation that comes from misplaced priorities.', NULL),
  (30, 'For all these things do the nations of the world seek after: and your Father knoweth that ye have need of these things.', 'ταῦτα γὰρ πάντα τὰ ἔθνη τοῦ κόσμου ἐπιζητοῦσιν· ὑμῶν δὲ ὁ πατὴρ οἶδεν ὅτι χρῄζετε τούτων.', 'tauta gar panta ta ethnē tou kosmou epizētousin; humōn de ho patēr oiden hoti chrēzete toutōn.', '"The nations of the world" (ta ethnē tou kosmou — Gentiles, pagans) pursue material security as the organizing principle of life. Disciples are not called to be post-material but to be differently motivated: "your Father knoweth" (oidEn — knows with complete, present knowledge) that you need these things. The Father''s omniscience makes anxious seeking redundant — he already knows before you ask (Matt 6:8).', NULL),
  (31, 'But rather seek ye the kingdom of God; and all these things shall be added unto you.', 'πλὴν ζητεῖτε τὴν βασιλείαν αὐτοῦ, καὶ ταῦτα πάντα προστεθήσεται ὑμῖν.', 'plēn zēteite tēn basileian autou, kai tauta panta prostethēsetai humin.', '"But rather" (plēn — however, on the contrary) — the great reorientation. The imperative "seek the kingdom" (zēteite tēn basileian) is the positive command replacing the forbidden seeking of v.29. "All these things shall be added" (prostethēsetai — future passive: will be added, granted additionally) — material provision is not pursued but received as the by-product of kingdom priority. The kingdom is sought; everything else is added.', NULL),
  (32, 'Fear not, little flock; for it is your Father''s good pleasure to give you the kingdom.', 'μὴ φοβοῦ, τὸ μικρὸν ποίμνιον· ὅτι εὐδόκησεν ὁ πατὴρ ὑμῶν δοῦναι ὑμῖν τὴν βασιλείαν.', 'mē phobou, to mikron poimnion; hoti eudokēsen ho patēr humōn dounai humin tēn basileian.', 'One of the tenderest verses in the Gospels. "Little flock" (mikron poimnion) — the smallness of the community is acknowledged without apology; what matters is whose flock it is. "Good pleasure" (eudokēsen — it pleased, he took delight in) — the kingdom is not given grudgingly or as a reward for seeking but from the Father''s joyful, sovereign delight. The kingdom is the gift behind all other gifts; to give the kingdom is to give everything.', NULL),
  (33, 'Sell that ye have, and give alms; provide yourselves bags which wax not old, a treasure in the heavens that faileth not, where no thief approacheth, neither moth corrupteth.', 'πωλήσατε τὰ ὑπάρχοντα ὑμῶν καὶ δότε ἐλεημοσύνην· ποιήσατε ἑαυτοῖς βαλλάντια μὴ παλαιούμενα, θησαυρὸν ἀνέκλειπτον ἐν τοῖς οὐρανοῖς, ὅπου κλέπτης οὐκ ἐγγίζει οὐδὲ σὴς διαφθείρει·', 'pōlēsate ta huparchonta humōn kai dote eleēmosunēn; poiēsate heautois ballantia mē palaioumena, thēsauron anekleippton en tois ouranois, hopou kleptēs ouk engizei oude sēs diaphtheirei;', 'The practical outworking of kingdom seeking: divestment from earthly security into heavenly investment through almsgiving. "Bags which wax not old" (ballantia mē palaioumena — purses that do not wear out) contrasts with the decaying barns of the rich fool. "Treasure in the heavens" (thēsauron anekleipston — inexhaustible, never-failing treasure) is protected from every earthly threat: theft (kleptēs) and decay (sēs — moth, corruption). Giving to the poor is depositing in the only truly secure account.', NULL),
  (34, 'For where your treasure is, there will your heart be also.', 'ὅπου γάρ ἐστιν ὁ θησαυρὸς ὑμῶν, ἐκεῖ καὶ ἡ καρδία ὑμῶν ἔσται.', 'hopou gar estin ho thēsauros humōn, ekei kai hē kardia humōn estai.', '"Heart" (kardia) in biblical thought is the center of will, intellect, and affection — the person''s true self. The investment of treasure creates the orientation of the whole person. This is not merely an observation about human psychology but a practical guide: if you want your heart to be with God, invest your treasure in God''s kingdom. The reverse is equally true: where treasure goes, the heart inevitably follows.', NULL),
  (35, 'Let your loins be girded about, and your lights burning;', 'Ἔστωσαν ὑμῶν αἱ ὀσφύες περιεζωσμέναι καὶ οἱ λύχνοι καόμενοι·', 'Estōsan humōn hai osphues periezōsmenai kai hoi luchnoi kaomenoi;', 'Two images of readiness: "loins girded" (osphues periezōsmenai — long robes tucked into the belt for unhindered movement, the Passover posture of Exod 12:11) and "lights burning" (luchnoi kaomenoi — lamps kept burning through the night). Both speak of sustained preparedness — not the sporadic excitement of occasional devotion but the continuous, costly alertness of servants who do not know the hour of the master''s return.', NULL),
  (36, 'And ye yourselves like unto men that wait for their lord, when he will return from the wedding; that when he cometh and knocketh, they may open unto him immediately.', 'καὶ ὑμεῖς ὅμοιοι ἀνθρώποις προσδεχομένοις τὸν κύριον ἑαυτῶν πότε ἀναλύσῃ ἐκ τῶν γάμων, ἵνα ἐλθόντος καὶ κρούσαντος εὐθέως ἀνοίξωσιν αὐτῷ.', 'kai humeis homoioi anthrōpois prosdechomenois ton kurion heautōn pote analusē ek tōn gamōn, hina elthontos kai krousantos eutheōs anoixōsin autō.', '"Wait for their lord" (prosdechomenois — expectantly receiving, actively welcoming) suggests not passive sitting but attentive orientation toward the expected arrival. A wedding feast could extend through the night — the master''s return was uncertain in timing. "Immediately" (eutheōs — at once, without delay) characterizes the readiness: the door should open the moment he knocks, with no scrambling or delay.', NULL),
  (37, 'Blessed are those servants, whom the lord when he cometh shall find watching: verily I say unto you, that he shall gird himself, and make them to sit down to meat, and will come forth and serve them.', 'μακάριοι οἱ δοῦλοι ἐκεῖνοι, οὓς ἐλθὼν ὁ κύριος εὑρήσει γρηγοροῦντας· ἀμὴν λέγω ὑμῖν ὅτι περιζώσεται καὶ ἀνακλινεῖ αὐτοὺς καὶ παρελθὼν διακονήσει αὐτοῖς.', 'makarioi hoi douloi ekeinoi, hous elthōn ho kurios heurēsei grēgorountas; amēn legō humin hoti perizōsetai kai anaklInei autous kai parelthōn diakonēsei autois.', 'A stunning reversal: the master girds himself and serves the servants who were watching. This is unique to Luke''s version of the parable and anticipates the Last Supper (22:27) where Jesus, as the master, serves. The faithful servant finds not greater labor at the master''s arrival but a reversal of roles: they are seated as guests (anaklInei — made to recline) while the Lord serves (diakonēsei — ministers, waiters upon). The eschatological banquet is the reward for faithful watchfulness.', NULL),
  (38, 'And if he shall come in the second watch, or come in the third watch, and find them so, blessed are those servants.', 'κἂν ἐν τῇ δευτέρᾳ κἂν ἐν τῇ τρίτῃ φυλακῇ ἔλθῃ καὶ εὕρῃ οὕτως, μακάριοί εἰσιν οἱ δοῦλοι ἐκεῖνοι.', 'kan en tē deutera kan en tē tritē phulakē elthē kai heurē houtōs, makarioi eisin hoi douloi ekeinoi.', 'Roman night watches divided the night into four watches (6pm-9pm, 9pm-12am, 12am-3am, 3am-6am). The second and third watches are the deepest, most difficult hours to remain alert. The beatitude is repeated for those who endure through the entire night of waiting — the perseverance of faith through long delay. The blessing is not contingent on the timing of the master''s return but on the posture maintained throughout.', NULL),
  (39, 'And this know, that if the goodman of the house had known what hour the thief would come, he would have watched, and not have suffered his house to be broken through.', 'τοῦτο δὲ γινώσκετε ὅτι εἰ ᾔδει ὁ οἰκοδεσπότης ποίᾳ ὥρᾳ ὁ κλέπτης ἔρχεται, ἐγρηγόρησεν ἂν καὶ οὐκ ἂν ἀφῆκεν διορυγῆναι τὸν οἶκον αὐτοῦ.', 'touto de ginōskete hoti ei ēdei ho oikodespotēs poia hōra ho kleptēs erchetai, egrēgorēsen an kai ouk an aphēken diorugēnai ton oikon autou.', 'A second parable: the homeowner who does not know when the thief comes. The analogy is not to equate Jesus with a thief but to emphasize the unpredictability of the hour. "Broken through" (diorugēnai — dug through, tunneled through the mud-brick walls of a Palestinian home) is the common form of ancient burglary. The point: ignorance of the hour requires constant watchfulness, since you cannot prepare only in the final moment.', NULL),
  (40, 'Be ye therefore ready also: for the Son of man cometh at an hour when ye think not.', 'καὶ ὑμεῖς γίνεσθε ἕτοιμοι, ὅτι ᾗ ὥρᾳ οὐ δοκεῖτε ὁ Υἱὸς τοῦ ἀνθρώπου ἔρχεται.', 'kai humeis ginesthe etoimoi, hoti hē hōra ou dokeite ho Huios tou anthrōpou erchetai.', '"Be ye ready" (ginesthe etoimoi — present imperative: keep becoming ready, maintain readiness) is the ongoing posture required. "The Son of man cometh at an hour when ye think not" (hē hōra ou dokeite — the hour you do not suppose, when you least expect it). The unexpectedness is not a threat but a pastoral call to continuous rather than crisis-based readiness. Disciples cannot afford spiritual vacation.', NULL),
  (41, 'Then Peter said unto him, Lord, speakest thou this parable unto us, or even to all?', 'Εἶπεν δὲ ὁ Πέτρος, Κύριε, πρὸς ἡμᾶς τὴν παραβολὴν ταύτην λέγεις ἢ καὶ πρὸς πάντας;', 'Eipen de ho Petros, Kurie, pros hēmas tēn parabolēn tautēn legeis ē kai pros pantas?', 'Peter''s question is pastoral and practical — he wants to know the scope of the parable''s application. Is it for the apostolic circle alone or for the entire crowd? Jesus''s answer does not directly answer but shifts to the faithful steward parable, implying that the parable applies especially to those in leadership who have specific responsibilities for others — Peter and the apostles most pointedly. The question implicitly separates leaders from the general crowd.', NULL),
  (42, 'And the Lord said, Who then is that faithful and wise steward, whom his lord shall make ruler over his household, to give them their portion of meat in due season?', 'καὶ εἶπεν ὁ Κύριος, Τίς ἄρα ἐστὶν ὁ πιστὸς οἰκονόμος ὁ φρόνιμος, ὃν καταστήσει ὁ κύριος ἐπὶ τῆς θεραπείας αὐτοῦ τοῦ διδόναι ἐν καιρῷ τὸ σιτομέτριον;', 'kai eipen ho Kurios, Tis ara estin ho pistos oikonomos ho phronimos, hon katastēsei ho kurios epi tēs therapeias autou tou didonai en kairō to sitometrion?', 'The "faithful and wise steward" (pistos oikonomos ho phronimos — the trustworthy and prudent estate manager) combines two qualities: faithfulness (pistos — reliability, trustworthiness to the master) and wisdom (phronimos — practical wisdom, prudence in administration). His task is to give the household "their portion of meat in due season" (en kairō to sitometrion — the measured grain-ration at the right time). This describes the teaching ministry: distributing the word of God appropriately and faithfully to the household of faith.', NULL),
  (43, 'Blessed is that servant, whom his lord when he cometh shall find so doing.', 'μακάριος ὁ δοῦλος ἐκεῖνος, ὃν ἐλθὼν ὁ κύριος αὐτοῦ εὑρήσει ποιοῦντα οὕτως.', 'makarios ho doulos ekeinos, hon elthōn ho kurios autou heurēsei poiounta houtōs.', '"Blessed is that servant" — the third beatitude in this chapter (vv.37,38,43). The blessing falls on the servant found actively doing his duty (poiōunta houtōs — doing thus, engaged in this task) at the moment of the master''s return. Faithfulness is not a dramatic achievement at the end but the daily practice of ordinary responsibility. The master finds him doing — present tense, continuous action — not preparing at the last moment.', NULL),
  (44, 'Of a truth I say unto you, that he will make him ruler over all that he hath.', 'ἀληθῶς λέγω ὑμῖν ὅτι ἐπὶ πᾶσιν τοῖς ὑπάρχουσιν αὐτοῦ καταστήσει αὐτόν.', 'alēthōs legō humin hoti epi pasin tois huparchousin autou katastēsei auton.', '"Of a truth" (alēthōs — truly, certainly) introduces a solemn promise. The reward for faithful stewardship over the household''s food is stewardship over "all that he hath" (pasin tois huparchousin autou — all his possessions). This echoes the parable of the minas (19:17: "have thou authority over ten cities") and establishes the pattern of kingdom reward: faithful small stewardship leads to greater responsibility, not retirement.', NULL),
  (45, 'But and if that servant say in his heart, My lord delayeth his coming; and shall begin to beat the menservants and maidens, and to eat and drink, and to be drunken;', 'ἐὰν δὲ εἴπῃ ὁ δοῦλος ἐκεῖνος ἐν τῇ καρδίᾳ αὐτοῦ, Χρονίζει ὁ κύριός μου ἔρχεσθαι, καὶ ἄρξηται τύπτειν τοὺς παῖδας καὶ τὰς παιδίσκας, ἐσθίειν τε καὶ πίνειν καὶ μεθύσκεσθαι,', 'ean de eipē ho doulos ekeinos en tē kardia autou, Chronizei ho kurios mou erchesthai, kai arxētai tuptein tous paidas kai tas paidiskas, esthiein te kai pinein kai methuskesthai,', 'The unfaithful servant''s sin begins not with violence but with a thought: "My lord delayeth" (Chronizei — is taking a long time, is delayed). Delayed return breeds entitlement, then abuse of authority. The servant begins to beat his fellow servants and indulge himself — the very opposite of the faithful steward''s distribution of provision. The abuse of power over those in one''s care (paidas kai paidiskas — men and women servants) is the specific manifestation of unfaithfulness.', NULL),
  (46, 'The lord of that servant will come in a day when he looketh not for him, and at an hour when he is not aware, and will cut him in sunder, and will appoint him his portion with the unbelievers.', 'ἥξει ὁ κύριος τοῦ δούλου ἐκείνου ἐν ἡμέρᾳ ᾗ οὐ προσδοκᾷ καὶ ἐν ὥρᾳ ᾗ οὐ γινώσκει, καὶ διχοτομήσει αὐτὸν καὶ τὸ μέρος αὐτοῦ μετὰ τῶν ἀπίστων θήσει.', 'hēxei ho kurios tou doulou ekeinou en hēmera hē ou prosdoka kai en hōra hē ou ginōskei, kai dichotomēsei auton kai to meros autou meta tōn apistōn thēsei.', '"Will cut him in sunder" (dichotomēsei — to cut in two, bisect) is a severe image, possibly referring to the ancient punishment of bisection or metaphorically to severe judgment. "With the unbelievers" (meta tōn apistōn — with the faithless ones) — the unfaithful steward is assigned to the category of those who had no faith at all. This is the solemn judgment on those who occupy positions of spiritual leadership while secretly dismissing the Lord''s return.', NULL),
  (47, 'And that servant, which knew his lord''s will, and prepared not himself, neither did according to his will, shall be beaten with many stripes.', 'ἐκεῖνος δὲ ὁ δοῦλος ὁ γνοὺς τὸ θέλημα τοῦ κυρίου αὐτοῦ καὶ μὴ ἑτοιμάσας ἢ ποιήσας πρὸς τὸ θέλημα αὐτοῦ δαρήσεται πολλάς·', 'ekeinos de ho doulos ho gnous to thelēma tou kuriou autou kai mē hetoimasas ē poiēsas pros to thelēma autou darēsetai pollas;', '"Knew his lord''s will" (gnous to thelēma — having known, with full knowledge) — knowledge increases accountability. The servant who knew and did not do will be beaten with many stripes. Knowledge of God''s will without corresponding obedience is not spiritual advantage but increased culpability. This principle applies most severely to those who have received clear scriptural instruction: teachers, preachers, and those long trained in the faith.', NULL),
  (48, 'But he that knew not, and did commit things worthy of stripes, shall be beaten with few stripes. For unto whomsoever much is given, of him shall be much required: and to whom men have committed much, of him they will ask the more.', 'ὁ δὲ μὴ γνούς, ποιήσας δὲ ἄξια πληγῶν, δαρήσεται ὀλίγας. παντὶ δὲ ᾧ ἐδόθη πολύ, πολὺ ζητηθήσεται παρ'' αὐτοῦ· καὶ ᾧ παρέθεντο πολύ, περισσότερον αἰτήσουσιν αὐτόν.', 'ho de mē gnous, poiēsas de axia plēgōn, darēsetai oligas. panti de hō edothē polu, polu zētēthēsetai par'' autou; kai hō parethento polu, perissoteron aitēsousin auton.', '"Unto whomsoever much is given, of him shall be much required" — one of the great organizing principles of the NT. Privilege entails accountability. This maxim applies across all domains: spiritual knowledge, material wealth, relational trust, vocational gifts. The one who received less revelation and acted wrongly in ignorance is judged proportionally less. This does not mean the ignorant escape judgment but that judgment calibrates to light received.', NULL),
  (49, 'I am come to send fire on the earth; and what will I, if it already be kindled?', 'Πῦρ ἦλθον βαλεῖν ἐπὶ τὴν γῆν, καὶ τί θέλω εἰ ἤδη ἀνήφθη.', 'Pur ēlthon balein epi tēn gēn, kai ti thelō ei ēdē anēphthē.', '"Fire" (pur) on the earth could refer to the fire of the Spirit (Acts 2:3: tongues of fire at Pentecost), the fire of eschatological judgment, or the fire of division and purification that Jesus''s coming would ignite. "What will I, if it already be kindled?" (ti thelō ei ēdē anēphthē) — "How I wish it were already kindled!" — expressing Jesus''s passionate longing for the completion of his mission, which the following verse (his baptism) will accomplish through suffering.', NULL),
  (50, 'But I have a baptism to be baptized with; and how am I straitened till it be accomplished!', 'βάπτισμα δὲ ἔχω βαπτισθῆναι, καὶ πῶς συνέχομαι ἕως οὗ τελεσθῇ.', 'baptisma de echō baptisthēnai, kai pōs sunechomai heōs hou telesthē.', '"A baptism to be baptized with" — the cross, described in baptismal imagery (cf. Mark 10:38-39). Baptism signifies death and new life; Jesus''s "baptism" is the overwhelming immersion in suffering, death, and the judgment of God (Ps 69:2,15; Isa 43:2). "How am I straitened" (sunechomai — I am constrained, pressed, held tight on all sides) reveals genuine internal anguish and longing for completion. This is one of the most revealing self-disclosures in Luke''s Gospel.', NULL),
  (51, 'Suppose ye that I am come to give peace on earth? I tell you, Nay; but rather division:', 'δοκεῖτε ὅτι εἰρήνην παρεγενόμην δοῦναι ἐν τῇ γῇ; οὐχί, λέγω ὑμῖν, ἀλλ'' ἢ διαμερισμόν.', 'dokeite hoti eirēnēn paregenomēn dounai en tē gē; ouchi, legō humin, all'' ē diamerismon.', '"Division" (diamerismon — division, splitting, distribution) — not Jesus''s personal goal but the inevitable result of his coming. He came to give peace with God (2:14; John 14:27; Rom 5:1), but his coming forces a decision that divides those who accept from those who reject, even within families. The shalom of messianic peace cannot coexist with comfort in sin; its arrival disrupts false peacetimes.', NULL),
  (52, 'For from henceforth there shall be five in one house divided, three against two, and two against three.', 'ἔσονται γὰρ ἀπὸ τοῦ νῦν πέντε ἐν ἑνὶ οἴκῳ διαμεμερισμένοι, τρεῖς ἐπὶ δυσὶν καὶ δύο ἐπὶ τρισίν.', 'esontai gar apo tou nun pente en heni oikō diamemerIsmenoi, treis epi dusin kai duo epi trisin.', '"From henceforth" (apo tou nun) — beginning with the ministry of Jesus, the eschatological crisis is underway and the division is already occurring. The household of five — a typical extended family — will split three against two. The mathematical precision (not even a simple majority) emphasizes that the division cuts through the most intimate structures of life, not merely the public or political sphere.', NULL),
  (53, 'The father shall be divided against the son, and the son against the father; the mother against the daughter, and the daughter against the mother; the mother in law against her daughter in law, and the daughter in law against her mother in law.', 'διαμερισθήσεται πατὴρ ἐπὶ υἱῷ καὶ υἱὸς ἐπὶ πατρί, μήτηρ ἐπὶ θυγατρί καὶ θυγάτηρ ἐπὶ μητρί, πενθερὰ ἐπὶ τὴν νύμφην αὐτῆς καὶ νύμφη ἐπὶ τὴν πενθεράν.', 'diameristhēsetai patēr epi huiō kai huios epi patri, mētēr epi thugatri kai thugatēr epi mētri, penthera epi tēn numphēn autēs kai numphē epi tēn pentheran.', 'This passage echoes Micah 7:6, applied now to the division caused by allegiance to Jesus. Every natural family bond — father/son, mother/daughter, mother-in-law/daughter-in-law — becomes a potential fault line. This is not a desirable outcome but an honest warning: loyalty to Jesus may cost the most precious earthly relationships. The disciple must count this cost (14:26) before committing.', NULL),
  (54, 'And he said also to the people, When ye see a cloud rise out of the west, straightway ye say, There cometh a shower; and so it is.', 'Ἔλεγεν δὲ καὶ τοῖς ὄχλοις, Ὅταν ἴδητε νεφέλην ἀνατέλλουσαν ἀπὸ δυσμῶν, εὐθέως λέγετε ὅτι Ὄμβρος ἔρχεται, καὶ γίνεται οὕτως·', 'Elegen de kai tois ochlois, Hotan idēte nephelēn anatEllousan apo dusmōn, eutheōs legete hoti Ombros erchetai, kai ginetai houtōs;', 'Jesus turns from the disciples to the crowd with a rebuke about discernment. In Palestine, a cloud rising from the west (the Mediterranean) reliably signals rain — the prevailing weather pattern. The crowd can read atmospheric signs with accuracy. The contrast with their inability to read spiritual signs (v.56) is the point of the rebuke. Natural discernment and spiritual discernment use the same faculty; the crowd applies it selectively.', NULL),
  (55, 'And when ye see the south wind blow, ye say, There will be heat; and it cometh to pass.', 'καὶ ὅταν νότον πνέοντα, λέγετε ὅτι Καύσων ἔσται, καὶ γίνεται.', 'kai hotan noton pneonta, legete hoti Kausōn estai, kai ginetai.', 'A south wind in Palestine brings hot, dry air from the desert (the sirocco). "Heat" (kauson — scorching heat, as in Jas 1:11) was a predictable consequence. Two weather signs, two accurate predictions. The people are not fools in reading nature; they are willfully blind in reading the signs of the messianic age. This makes their spiritual blindness more culpable, not less, since it is selective rather than universal.', NULL),
  (56, 'Ye hypocrites, ye can discern the face of the sky and of the earth; but how is it that ye do not discern this time?', 'ὑποκριταί, τὸ πρόσωπον τῆς γῆς καὶ τοῦ οὐρανοῦ οἴδατε δοκιμάζειν, τὸν δὲ καιρὸν τοῦτον πῶς οὐκ οἴδατε δοκιμάζειν;', 'hupokritai, to prosōpon tēs gēs kai tou ouranou oidate dokimazein, ton de kairon touton pōs ouk oidate dokimazein?', '"Hypocrites" (hupokritai) — applied here not to moral deceit but to selective use of perception. They have the faculty of discernment (dokimazein — to test, examine, evaluate, the word used for testing metals for genuineness) but apply it only to nature, not to "this time" (ton kairon touton — this decisive moment, the kairos of messianic fulfillment). The crisis of the present hour — the kingdom arriving in Jesus — demands the same careful reading they give to weather patterns.', NULL),
  (57, 'Yea, and why even of yourselves judge ye not what is right?', 'τί δὲ καὶ ἀφ'' ἑαυτῶν οὐ κρίνετε τὸ δίκαιον;', 'ti de kai aph'' heautōn ou krinete to dikaion?', 'An appeal to moral intuition: even apart from prophetic revelation or messianic signs, their own moral reasoning should tell them that repentance and reconciliation are right (to dikaion — the just thing, what is right). The question exposes not ignorance but suppression of conscience. Every person has sufficient moral light to recognize the need for righteousness; the failure to act on it is willful, not uninformed.', NULL),
  (58, 'When thou goest with thine adversary to the magistrate, as thou art in the way, give diligence that thou mayest be delivered from him; lest he hale thee to the judge, and the judge deliver thee to the officer, and the officer cast thee into prison.', 'ὡς γὰρ ὑπάγεις μετὰ τοῦ ἀντιδίκου σου ἐπ'' ἄρχοντα, ἐν τῇ ὁδῷ δὸς ἐργασίαν ἀπηλλάχθαι ἀπ'' αὐτοῦ, μήποτε κατασύρῃ σε πρὸς τὸν κριτήν, καὶ ὁ κριτής σε παραδώσῃ τῷ πράκτορι, καὶ ὁ πράκτωρ σε βαλεῖ εἰς φυλακήν.', 'hōs gar hupageis meta tou antidikou sou ep'' archonta, en tē hodō dos ergasian apēllachthai ap'' autou, mēpote katasurē se pros ton kritēn, kai ho kritēs se paradōsē tō praktori, kai ho praktōr se balei eis phulakēn.', '"Adversary" (antidikou — legal opponent) and the whole legal chain (magistrate → judge → officer → prison) mirrors the urgency of the spiritual moment. "Give diligence" (dos ergasian — make effort, work hard) to settle the case before judgment is rendered. Applied spiritually: the crowd is on the way to judgment; the time before the final verdict is now, and reconciliation with God is urgent while there is opportunity.', NULL),
  (59, 'I tell thee, thou shalt not depart thence, till thou hast paid the very last mite.', 'λέγω σοι, οὐ μὴ ἐξέλθῃς ἐκεῖθεν ἕως καὶ τὸ ἔσχατον λεπτὸν ἀποδῷς.', 'legō soi, ou mē exelthēs ekeithen heōs kai to eschaton lepton apodōs.', '"The very last mite" (to eschaton lepton — the last lepton, the smallest coin in circulation, worth about 1/8 of a cent) — complete, exhaustive payment is required for release. In the judicial image, debts must be paid in full; in the spiritual application, the wages of sin (Rom 6:23) cannot be partially repaid. The urgency of the entire chapter converges here: reconcile now, respond to the kingdom now, before the judgment seat makes all reckoning irrevocable.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 12;
